mapper.select:
SELECT c.id, c.user_id, c.product_id, c.quantity, c.created_time, c.updated_time, p.name AS product_name, p.price AS product_price, p.stock AS product_stock, p.reserved_stock AS product_reserved_stock, p.category AS product_category FROM cart c LEFT JOIN product p ON c.product_id = p.id WHERE c.user_id = #{userId} AND c.id IN
#{id}
ORDER BY c.updated_time DESC
